 1→import React from 'react';
 2→import { StyleProp, StyleSheet, ViewStyle } from 'react-native';
 3→import Animated, { FadeInDown } from 'react-native-reanimated';
 4→
 5→import { colors } from '../theme/colors';
 6→import { elevation as elevationTokens } from '../theme/elevation';
 7→
 8→type ElevationLevel = 0 | 1 | 2 | 3;
 9→
10→interface CardProps {
11→  children: React.ReactNode;
12→  elevation?: ElevationLevel;
13→  style?: StyleProp<ViewStyle>;
14→  entering?: typeof FadeInDown;
15→}
16→
17→const elevationMap = {
18→  0: elevationTokens.level0,
19→  1: elevationTokens.level1,
20→  2: elevationTokens.level2,
21→  3: elevationTokens.level3,
22→};
23→
24→export function Card({ children, elevation = 1, style, entering }: CardProps) {
25→  return (
26→    <Animated.View
27→      entering={entering ?? FadeInDown.duration(300)}
28→      style={[styles.card, elevationMap[elevation], style]}
29→    >
30→      {children}
31→    </Animated.View>
32→  );
33→}
34→
35→const styles = StyleSheet.create({
36→  card: {
37→    borderRadius: 24,
38→    backgroundColor: colors.surface,
39→    padding: 18,
40→    borderWidth: 1,
41→    borderColor: colors.line,
42→  },
43→});
