 1→import React from 'react';
 2→import { StyleSheet, Text } from 'react-native';
 3→import Animated, {
 4→  interpolateColor,
 5→  useAnimatedStyle,
 6→  useSharedValue,
 7→  withSpring,
 8→} from 'react-native-reanimated';
 9→
10→import { colors } from '../theme/colors';
11→import { motion } from '../theme/motion';
12→import { AnimatedPressable } from './AnimatedPressable';
13→
14→interface ChipProps {
15→  label: string;
16→  selected: boolean;
17→  onPress: () => void;
18→  accessibilityLabel?: string;
19→}
20→
21→export const Chip = React.memo(function Chip({
22→  label,
23→  selected,
24→  onPress,
25→  accessibilityLabel,
26→}: ChipProps) {
27→  const progress = useSharedValue(selected ? 1 : 0);
28→  progress.value = withSpring(selected ? 1 : 0, motion.snappy);
29→
30→  const animatedStyle = useAnimatedStyle(() => ({
31→    backgroundColor: interpolateColor(
32→      progress.value,
33→      [0, 1],
34→      [colors.surfaceAlt, colors.brandLight]
35→    ),
36→    borderColor: interpolateColor(
37→      progress.value,
38→      [0, 1],
39→      [colors.line, colors.brand]
40→    ),
41→    transform: [{ scale: withSpring(selected ? 1.02 : 1, motion.bouncy) }],
42→  }));
43→
44→  return (
45→    <AnimatedPressable
46→      onPress={onPress}
47→      accessibilityRole="tab"
48→      accessibilityState={{ selected }}
49→      accessibilityLabel={accessibilityLabel ?? label}
50→    >
51→      <Animated.View style={[styles.chip, animatedStyle]}>
52→        <Text style={styles.chipText}>{label}</Text>
53→      </Animated.View>
54→    </AnimatedPressable>
55→  );
56→});
57→
58→const styles = StyleSheet.create({
59→  chip: {
60→    borderRadius: 999,
61→    paddingHorizontal: 14,
62→    paddingVertical: 10,
63→    borderWidth: 1,
64→  },
65→  chipText: {
66→    color: colors.ink,
67→    fontWeight: '700',
68→  },
69→});
