  1→import React, { useState } from 'react';
  2→import { StyleSheet, TextInput, View } from 'react-native';
  3→import Animated, {
  4→  interpolateColor,
  5→  useAnimatedStyle,
  6→  useSharedValue,
  7→  withSpring,
  8→  withTiming,
  9→} from 'react-native-reanimated';
 10→
 11→import { colors } from '../theme/colors';
 12→import { motion } from '../theme/motion';
 13→import { AnimatedPressable } from './AnimatedPressable';
 14→
 15→interface SearchBarProps {
 16→  value: string;
 17→  onChangeText: (text: string) => void;
 18→  placeholder?: string;
 19→}
 20→
 21→export function SearchBar({ value, onChangeText, placeholder = 'Search...' }: SearchBarProps) {
 22→  const focused = useSharedValue(0);
 23→  const [isFocused, setIsFocused] = useState(false);
 24→
 25→  const borderStyle = useAnimatedStyle(() => ({
 26→    borderColor: interpolateColor(
 27→      focused.value,
 28→      [0, 1],
 29→      [colors.line, colors.brand]
 30→    ),
 31→  }));
 32→
 33→  const clearOpacity = useAnimatedStyle(() => ({
 34→    opacity: withTiming(value.length > 0 ? 1 : 0, { duration: 150 }),
 35→  }));
 36→
 37→  return (
 38→    <Animated.View
 39→      style={[styles.container, borderStyle]}
 40→      accessibilityRole="search"
 41→    >
 42→      <Animated.Text style={styles.icon}>
 43→        {'\u{1F50D}'}
 44→      </Animated.Text>
 45→      <TextInput
 46→        style={styles.input}
 47→        value={value}
 48→        onChangeText={onChangeText}
 49→        placeholder={placeholder}
 50→        placeholderTextColor={colors.mutedInk}
 51→        onFocus={() => {
 52→          focused.value = withSpring(1, motion.snappy);
 53→          setIsFocused(true);
 54→        }}
 55→        onBlur={() => {
 56→          focused.value = withSpring(0, motion.snappy);
 57→          setIsFocused(false);
 58→        }}
 59→        accessibilityLabel={placeholder}
 60→      />
 61→      {value.length > 0 && (
 62→        <Animated.View style={clearOpacity}>
 63→          <AnimatedPressable
 64→            onPress={() => onChangeText('')}
 65→            accessibilityLabel="Clear search"
 66→            accessibilityRole="button"
 67→          >
 68→            <View style={styles.clearButton}>
 69→              <Animated.Text style={styles.clearText}>X</Animated.Text>
 70→            </View>
 71→          </AnimatedPressable>
 72→        </Animated.View>
 73→      )}
 74→    </Animated.View>
 75→  );
 76→}
 77→
