 1→import React from 'react';
 2→import { StyleSheet, View } from 'react-native';
 3→import Animated, { useAnimatedStyle, withSpring } from 'react-native-reanimated';
 4→
 5→import { colors } from '../theme/colors';
 6→import { motion } from '../theme/motion';
 7→
 8→interface ProgressBarProps {
 9→  progress: number; // 0-1
10→  color?: string;
11→  height?: number;
12→  accessibilityLabel?: string;
13→}
14→
15→export function ProgressBar({
16→  progress,
17→  color = colors.brand,
18→  height = 6,
19→  accessibilityLabel = 'Progress',
20→}: ProgressBarProps) {
21→  const clamped = Math.min(1, Math.max(0, progress));
22→
23→  const fillStyle = useAnimatedStyle(() => ({
24→    width: `${withSpring(clamped * 100, motion.gentle)}%` as any,
25→  }));
26→
27→  return (
28→    <View
29→      style={[styles.track, { height }]}
30→      accessibilityRole="progressbar"
31→      accessibilityLabel={accessibilityLabel}
32→      accessibilityValue={{ min: 0, max: 100, now: Math.round(clamped * 100) }}
33→    >
34→      <Animated.View style={[styles.fill, { backgroundColor: color, height }, fillStyle]} />
35→    </View>
36→  );
37→}
38→
39→const styles = StyleSheet.create({
40→  track: {
41→    borderRadius: 999,
42→    backgroundColor: colors.line,
43→    overflow: 'hidden',
44→  },
45→  fill: {
46→    borderRadius: 999,
47→  },
48→});
