  1→import { BottomTabBarProps } from '@react-navigation/bottom-tabs';
  2→import React, { useCallback, useState } from 'react';
  3→import { LayoutChangeEvent, StyleSheet, Text, View } from 'react-native';
  4→import Animated from 'react-native-reanimated';
  5→
  6→import { useAppStore } from '../../state/useAppStore';
  7→import { colors } from '../../theme/colors';
  8→import { elevation } from '../../theme/elevation';
  9→import { AnimatedPressable } from '../AnimatedPressable';
 10→import { TabBarBadge } from './TabBarBadge';
 11→import { TabBarIcon } from './TabBarIcon';
 12→import { TabBarIndicatorPill } from './TabBarIndicatorPill';
 13→import { tabBarIcons } from './tabBarIcons';
 14→
 15→export function GrockTabBar({ state, descriptors, navigation }: BottomTabBarProps) {
 16→  const [tabWidth, setTabWidth] = useState(0);
 17→  const appState = useAppStore(s => s.appState);
 18→
 19→  const cartItemCount = appState
 20→    ? appState.vault.carts
 21→        .filter(c => !c.isDeleted && c.status !== 'completed')
 22→        .reduce((sum, c) => sum + c.cartItems.length, 0)
 23→    : 0;
 24→
 25→  const onLayout = useCallback((e: LayoutChangeEvent) => {
 26→    const width = e.nativeEvent.layout.width;
 27→    setTabWidth(width / state.routes.length);
 28→  }, [state.routes.length]);
 29→
 30→  return (
 31→    <View
 32→      style={styles.container}
 33→      onLayout={onLayout}
 34→      accessibilityRole="tablist"
 35→    >
 36→      {tabWidth > 0 && (
 37→        <TabBarIndicatorPill
 38→          tabCount={state.routes.length}
 39→          activeIndex={state.index}
 40→          tabWidth={tabWidth}
 41→        />
 42→      )}
 43→      {state.routes.map((route, index) => {
 44→        const { options } = descriptors[route.key];
 45→        const isFocused = state.index === index;
 46→        const routeName = route.name as keyof typeof tabBarIcons;
 47→
 48→        const onPress = () => {
 49→          const event = navigation.emit({
 50→            type: 'tabPress',
 51→            target: route.key,
 52→            canPreventDefault: true,
 53→          });
 54→          if (!isFocused && !event.defaultPrevented) {
 55→            navigation.navigate(route.name);
 56→          }
 57→        };
 58→
 59→        const label = options.tabBarLabel
 60→          ? String(options.tabBarLabel)
 61→          : options.title ?? route.name;
 62→
 63→        const badgeCount = routeName === 'Cart' ? cartItemCount : 0;
 64→        const accessibilityLabel = badgeCount > 0
 65→          ? `${label}, ${badgeCount} item${badgeCount === 1 ? '' : 's'}`
 66→          : label;
 67→
 68→        return (
 69→          <AnimatedPressable
 70→            key={route.key}
 71→            onPress={onPress}
 72→            style={styles.tab}
 73→            accessibilityRole="tab"
 74→            accessibilityState={{ selected: isFocused }}
 75→            accessibilityLabel={accessibilityLabel}
 76→          >
 77→            <View>
 78→              <TabBarIcon routeName={routeName} focused={isFocused} />
 79→              {routeName === 'Cart' && <TabBarBadge count={badgeCount} />}
 80→            </View>
 81→            <Text style={[styles.label, isFocused && styles.labelActive]}>
 82→              {label}
 83→            </Text>
 84→          </AnimatedPressable>
 85→        );
 86→      })}
 87→    </View>
 88→  );
 89→}
 90→
 91→const styles = StyleSheet.create({
 92→  container: {
 93→    flexDirection: 'row',
 94→    height: 80,
 95→    backgroundColor: colors.surface,
 96→    borderTopWidth: 1,
 97→    borderTopColor: colors.line,
 98→    paddingBottom: 8,
 99→    ...elevation.level3,
100→  },
101→  tab: {
102→    flex: 1,
103→    alignItems: 'center',
104→    justifyContent: 'center',
105→    gap: 4,
106→    minHeight: 48,
107→    minWidth: 48,
108→  },
109→  label: {
110→    fontSize: 12,
111→    color: colors.mutedInk,
112→    fontWeight: '600',
113→  },
114→  labelActive: {
115→    color: colors.brand,
116→    fontWeight: '700',
117→  },
118→});
