334→export function computeDashboardSummary(state: VaultAppState): DashboardSummary {
335→  const activeCarts = state.vault.carts.filter(cart => !cart.isDeleted && cart.status !== 'completed');
336→  const completedCarts = state.vault.carts.filter(cart => !cart.isDeleted && cart.status === 'completed');
337→  const cartTotals = completedCarts.map(cart => ({ cart, total: computeCartTotal(state.vault, cart) }));
338→  const totalSpent = cartTotals.reduce((sum, entry) => sum + entry.total, 0);
339→  const overBudgetCount = cartTotals.filter(entry => entry.total > entry.cart.budget).length;
340→  const itemCount = state.vault.categories.reduce((sum, category) => sum + category.items.length, 0);
341→
342→  return {
343→    activeCarts,
344→    completedCarts,
345→    totalSpent,
346→    overBudgetCount,
347→    itemCount,
348→  };
349→}
