 25→export function VaultScreen() {
 26→  const appState = useAppStore(state => state.appState);
 27→  const draftSelections = useAppStore(state => state.draftSelections);
 28→  const toggleDraftItem = useAppStore(state => state.toggleDraftItem);
 29→  const setDraftQuantity = useAppStore(state => state.setDraftQuantity);
 30→  const addCategory = useAppStore(state => state.addCategory);
 31→  const addItem = useAppStore(state => state.addItem);
 32→  const deleteItem = useAppStore(state => state.deleteItem);
 33→
 34→  const [search, setSearch] = useState('');
 35→  const [filterCategoryId, setFilterCategoryId] = useState('');
 36→  const [showAddItem, setShowAddItem] = useState(false);
 37→  const [showAddCategory, setShowAddCategory] = useState(false);
 38→
 39→  const sections: Section[] = useMemo(() => {
 40→    if (!appState) return [];
 41→    const query = search.trim().toLowerCase();
 42→
 43→    return appState.vault.categories
 44→      .slice()
 45→      .sort((a, b) => a.sortOrder - b.sortOrder)
 46→      .filter(cat => {
 47→        if (filterCategoryId && cat.uid !== filterCategoryId) return false;
 48→        if (!query) return true;
 49→        return (
 50→          cat.name.toLowerCase().includes(query) ||
 51→          cat.items.some(item => item.name.toLowerCase().includes(query))
 52→        );
 53→      })
 54→      .map(cat => {
 55→        const filteredItems = query
 56→          ? cat.items.filter(item => item.name.toLowerCase().includes(query))
 57→          : cat.items;
 58→        return { category: cat, data: filteredItems };
 59→      });
 60→  }, [appState, search, filterCategoryId]);
 61→
 62→  const handleAddItem = useCallback(
 63→    async (categoryId: string, name: string, store: string, price: number, unit: string, description: string) => {
 64→      await addItem({ categoryId, name, store, price, unit, description });
 65→      setShowAddItem(false);
 66→    },
 67→    [addItem]
 68→  );
 69→
 70→  const handleDeleteItem = useCallback(
 71→    (item: Item) => {
 72→      Alert.alert('Delete item?', `This will remove ${item.name} from your vault.`, [
 73→        { text: 'Cancel', style: 'cancel' },
 74→        {
 75→          text: 'Delete',
 76→          style: 'destructive',
 77→          onPress: () => {
 78→            deleteItem(item.id).catch(() => undefined);
 79→          },
 80→        },
 81→      ]);
 82→    },
 83→    [deleteItem]
 84→  );
 85→
 86→  const handleAddCategory = useCallback(
 87→    async (name: string, emoji: string) => {
 88→      await addCategory(name, emoji);
 89→      setShowAddCategory(false);
 90→    },
 91→    [addCategory]
 92→  );
 93→
 94→  const renderItem = useCallback(
 95→    ({ item }: { item: Item }) => {
 96→      const quantity = draftSelections[item.id] ?? 0;
 97→      return (
 98→        <VaultItemCard
 99→          item={item}
100→          quantity={quantity}
101→          onToggle={() => toggleDraftItem(item.id)}
102→          onIncrement={() => setDraftQuantity(item.id, quantity + 1)}
103→          onDecrement={() => setDraftQuantity(item.id, Math.max(1, quantity - 1))}
104→          onDelete={() => handleDeleteItem(item)}
105→        />
106→      );
107→    },
108→    [draftSelections, toggleDraftItem, setDraftQuantity, handleDeleteItem]
109→  );
110→
111→  const renderSectionHeader = useCallback(
112→    ({ section }: { section: Section }) => (
113→      <VaultSectionHeader
114→        emoji={section.category.emoji}
115→        name={section.category.name}
116→        count={section.data.length}
117→      />
118→    ),
119→    []
120→  );
121→
122→  const getItemLayout = useCallback(
123→    (_data: any, index: number) => ({
124→      length: ITEM_HEIGHT,
125→      offset: ITEM_HEIGHT * index,
126→      index,
127→    }),
128→    []
129→  );
130→
131→  if (!appState) return null;
132→
133→  return (
134→    <GestureHandlerRootView style={styles.screen}>
135→      <SectionList
136→        sections={sections}
137→        keyExtractor={item => item.id}
138→        renderItem={renderItem}
139→        renderSectionHeader={renderSectionHeader}
140→        getItemLayout={getItemLayout}
141→        stickySectionHeadersEnabled
142→        ListHeaderComponent={
143→          <View style={styles.header}>
144→            <VaultSearchBar value={search} onChangeText={setSearch} />
145→            <CategoryChipRow
146→              categories={appState.vault.categories}
147→              selectedId={filterCategoryId}
148→              onSelect={setFilterCategoryId}
149→            />
150→          </View>
151→        }
152→        ListEmptyComponent={<VaultEmptyState />}
153→        contentContainerStyle={styles.content}
154→        initialNumToRender={10}
155→        maxToRenderPerBatch={5}
156→        windowSize={5}
157→        ItemSeparatorComponent={ItemSeparator}
158→      />
159→
160→      {!showAddItem && !showAddCategory && (
161→        <VaultFAB
162→          onAddItem={() => setShowAddItem(true)}
163→          onAddCategory={() => setShowAddCategory(true)}
164→        />
165→      )}
166→
167→      {showAddItem && (
168→        <AddItemSheet
169→          categories={appState.vault.categories}
170→          onSubmit={(catId, name, store, price, unit, description) => {
171→            handleAddItem(catId, name, store, price, unit, description).catch(() => undefined);
172→          }}
173→          onClose={() => setShowAddItem(false)}
174→        />
175→      )}
176→
177→      {showAddCategory && (
178→        <AddCategorySheet
179→          onSubmit={(name, emoji) => {
180→            handleAddCategory(name, emoji).catch(() => undefined);
181→          }}
182→          onClose={() => setShowAddCategory(false)}
183→        />
184→      )}
185→    </GestureHandlerRootView>
186→  );
187→}
