 4→import Svg, { Circle } from 'react-native-svg';
 5→
 6→import { colors } from '../../../theme/colors';
 7→import { motion } from '../../../theme/motion';
 8→
 9→const AnimatedCircle = Animated.createAnimatedComponent(Circle);
10→
11→interface CartProgressRingProps {
12→  progress: number; // 0-1
13→  size?: number;
14→  strokeWidth?: number;
15→}
16→
17→export function CartProgressRing({
18→  progress,
19→  size = 64,
20→  strokeWidth = 5,
21→}: CartProgressRingProps) {
22→  const radius = (size - strokeWidth) / 2;
23→  const circumference = 2 * Math.PI * radius;
24→  const clamped = Math.min(1, Math.max(0, progress));
25→
26→  const animatedProps = useAnimatedProps(() => ({
27→    strokeDashoffset: withSpring(circumference * (1 - clamped), motion.gentle),
28→  }));
29→
30→  return (
31→    <View
32→      style={[styles.container, { width: size, height: size }]}
33→      accessibilityRole="progressbar"
34→      accessibilityValue={{ min: 0, max: 100, now: Math.round(clamped * 100) }}
35→      accessibilityLabel={`Cart progress: ${Math.round(clamped * 100)}%`}
36→    >
37→      <Svg width={size} height={size}>
38→        <Circle
39→          cx={size / 2}
40→          cy={size / 2}
41→          r={radius}
42→          stroke={colors.line}
43→          strokeWidth={strokeWidth}
44→          fill="none"
45→        />
46→        <AnimatedCircle
47→          cx={size / 2}
48→          cy={size / 2}
49→          r={radius}
50→          stroke={colors.brand}
51→          strokeWidth={strokeWidth}
52→          fill="none"
53→          strokeDasharray={circumference}
54→          animatedProps={animatedProps}
55→          strokeLinecap="round"
56→          rotation="-90"
57→          origin={`${size / 2}, ${size / 2}`}
58→        />
59→      </Svg>
60→    </View>
61→  );
62→}
