43→      fillOpacity.value = withTiming(0, { duration: 100 });
44→    }
45→  }, [isFulfilled, scale, fillOpacity]);
46→
47→  const animatedStyle = useAnimatedStyle(() => ({
48→    transform: [{ scale: scale.value }],
49→    opacity: fillOpacity.value,
