  4→import Animated, {
  5→  runOnJS,
  6→  useAnimatedStyle,
  7→  useSharedValue,
  8→  withSpring,
  9→} from 'react-native-reanimated';
 10→import MaterialCommunityIcons from 'react-native-vector-icons/MaterialCommunityIcons';
 11→
