import React from 'react';
import { ScrollView, StyleSheet, Text, View } from 'react-native';

import { computeCartTotal } from '../../domain/models';
import { formatCurrency, formatDate } from '../../lib/format';
import { useAppStore } from '../../state/useAppStore';
import { colors } from '../../theme/colors';

export function HistoryScreen() {
  const appState = useAppStore(state => state.appState);

  if (!appState) {
    return null;
  }

  const completed = appState.vault.carts.filter(cart => cart.status === 'completed' && !cart.isDeleted);

  return (
    <ScrollView style={styles.screen} contentContainerStyle={styles.content}>
      <Text style={styles.title}>History</Text>
      <Text style={styles.subtitle}>Completed carts and the totals they closed with.</Text>

      {completed.length ? (
        completed.map(cart => (
          <View key={cart.id} style={styles.card}>
            <Text style={styles.cardTitle}>{cart.name}</Text>
            <Text style={styles.cardCopy}>Completed {formatDate(cart.completedAt)}</Text>
            <Text style={styles.total}>{formatCurrency(computeCartTotal(appState.vault, cart))}</Text>
          </View>
        ))
      ) : (
        <View style={styles.card}>
          <Text style={styles.cardTitle}>No history yet</Text>
          <Text style={styles.cardCopy}>Complete a shopping trip to populate this screen.</Text>
        </View>
      )}
    </ScrollView>
  );
}

const styles = StyleSheet.create({
  screen: {
    flex: 1,
    backgroundColor: colors.canvas,
  },
  content: {
    padding: 20,
    gap: 14,
  },
  title: {
    fontSize: 30,
    fontWeight: '800',
    color: colors.ink,
  },
  subtitle: {
    color: colors.mutedInk,
  },
  card: {
    borderRadius: 20,
    backgroundColor: colors.surface,
    borderWidth: 1,
    borderColor: colors.line,
    padding: 16,
    gap: 6,
  },
  cardTitle: {
    color: colors.ink,
    fontWeight: '800',
    fontSize: 17,
  },
  cardCopy: {
    color: colors.mutedInk,
  },
  total: {
    color: colors.brandDeep,
    fontWeight: '800',
    fontSize: 18,
    marginTop: 6,
  },
});

import { ViewStyle } from 'react-native';

export const elevation = {
  level0: {
    elevation: 0,
    shadowColor: 'transparent',
    shadowOffset: { width: 0, height: 0 },
    shadowOpacity: 0,
    shadowRadius: 0,
  } as ViewStyle,
  level1: {
    elevation: 1,
    shadowColor: '#211c16',
    shadowOffset: { width: 0, height: 1 },
    shadowOpacity: 0.05,
    shadowRadius: 3,
  } as ViewStyle,
  level2: {
    elevation: 3,
    shadowColor: '#211c16',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.08,
    shadowRadius: 6,
  } as ViewStyle,
  level3: {
    elevation: 6,
    shadowColor: '#211c16',
    shadowOffset: { width: 0, height: 4 },
    shadowOpacity: 0.12,
    shadowRadius: 12,
  } as ViewStyle,
} as const;

import { ReduceMotion, WithSpringConfig } from 'react-native-reanimated';

const base = { reduceMotion: ReduceMotion.System } as const;

export const motion = {
  snappy: {
    ...base,
    damping: 20,
    stiffness: 300,
    mass: 0.8,
  } satisfies WithSpringConfig,
  gentle: {
    ...base,
    damping: 20,
    stiffness: 120,
    mass: 1,
  } satisfies WithSpringConfig,
  bouncy: {
    ...base,
    damping: 12,
    stiffness: 180,
    mass: 0.8,
  } satisfies WithSpringConfig,
  quick: {
    ...base,
    damping: 26,
    stiffness: 400,
    mass: 0.6,
  } satisfies WithSpringConfig,
} as const;

